import java.util.*;

public int minMonths(int n, int[][] relations, int[] time) {
    int[] order = new int[n];
    for (int[] r : relations)
        order[r[1] - 1] = Math.max(order[r[1] - 1], r[0]);
    int totalTime = 0;
    for (int i = 0; i < n; i++)
        totalTime = Math.max(totalTime, time[i] + order[i]);
    return totalTime;
}
```

